class Solution:
    def minimumOperations(self, num: str) -> int:
        # Check if the number is already divisible by 25
        if int(num) % 25 == 0:
            return 0

        # Try all possible suffixes that make a number divisible by 25
        targets = ["00", "25", "50", "75"]
        min_deletions = float('inf')

        for target in targets:
            i = len(num) - 1
            j = len(target) - 1
            deletions = 0

            # Find the suffix matching the target
            while i >= 0 and j >= 0:
                if num[i] == target[j]:
                    j -= 1
                else:
                    deletions += 1
                i -= 1

            # If we found the target, update min_deletions
            if j == -1:
                min_deletions = min(min_deletions, deletions)

        # If no valid suffix is found, the only option is to delete all digits to get 0
        return min_deletions if min_deletions != float('inf') else len(num) - 1
